import 'package:flutter/material.dart';import 'package:go_router/go_router.dart';import '../../core/utils/date_time_utils.dart';import '../../core/widgets/countdown_text.dart';import '../../core/widgets/error_view.dart';import '../../core/widgets/loading_view.dart';import '../../core/widgets/match_status_badge.dart';import '../../services/fixture_service.dart';
class FixturesScreen extends StatelessWidget{const FixturesScreen({super.key});@override Widget build(BuildContext c)=>Scaffold(appBar:AppBar(title:const Text('Fixtures')),body:FutureBuilder(future:FixtureService().fixtures(),builder:(c,s){if(s.connectionState==ConnectionState.waiting)return const LoadingView();if(s.hasError)return ErrorView(message:'Could not load fixtures',onRetry:()=> (c as Element).markNeedsBuild());final list=s.data??[];return ListView.builder(padding:const EdgeInsets.all(12),itemCount:list.length,itemBuilder:(c,i){final f=list[i];return Card(child:ListTile(onTap:()=>c.go('/fixtures/${f.id}'),title:Text(f.matchTitle),subtitle:Column(crossAxisAlignment:CrossAxisAlignment.start,children:[Text('${f.stage} • ${f.teamAName} vs ${f.teamBName}'),Text(DateTimeUtils.format(f.matchStartAt)),CountdownText(target:f.matchStartAt),if(f.teamAScore!=null&&f.teamBScore!=null)Text('Score: ${f.teamAScore}-${f.teamBScore}')]),trailing:MatchStatusBadge(label:f.predictionStatus)));});}));}
